@startuml
!theme plain

class "SubtractExpression" as SubtractExpression {
  leftExpression IExpression
  rightExpression IExpression
  SubtractExpression(left IExpression, right IExpression)
  Interpret(context Context) int
}

class "AddExpression" as AddExpression {
  leftExpression IExpression
  rightExpression IExpression
  AddExpression(left IExpression, right IExpression)
  Interpret(context Context) int
}

class "NumberExpression" as NumberExpression {
  name string
  NumberExpression(variableName string)
  Interpret(context Context) int
}

class "Context" as Context {
  variables: Dictionary<string, int>
  Context()
  GetVariable(name string) int
  SetVariable(name string, value int)
}

class "Program" as Program {
  Main(args[] string)
}

class "IExpression" as IExpression {
  Interpret(context Context) int
}

SubtractExpression --|> IExpression
AddExpression --|> IExpression
NumberExpression --|> IExpression
Program --> Context
Program --> IExpression

@enduml
